class Solution {
public:
    int minimumSteps(string s) {
        int n = s.length();
        int countBlack = 0;
        int countWhite = n - 1;

        for (int i = 1; i < n; i++) {
            if (s[i] == '0') {
                countBlack++;
            } else {
                countWhite--;
            }
        }

        int steps = countWhite - countBlack;

        if (steps < 0) {
            steps += n;
        }

        return steps;
    }
};
```

